from a2a.types import AgentCapabilities, AgentCard, AgentSkillskill = AgentSkill(id='receipe',                   name='Returns recipe information',                   description='just returns recipe information',                   tags=['recipe', 'food', 'lunch'],                   examples=['How to make a pizza?', 'Suggest a recipe'],                   inputModes=['text/plain'],                   outputModes=['text/plain'])agent_port = 8888public_agent_card = AgentCard(name='Recipe Agent',                              description='A recipe agent',                              url=f'http://localhost:{agent_port}/',                              version='1.0.0',                              default_input_modes=['text'],                              default_output_modes=['text'],                              capabilities=AgentCapabilities(streaming=True),                              skills=[skill])from a2a.server.apps import A2AStarletteApplicationfrom a2a.server.request_handlers import DefaultRequestHandlerfrom a2a.server.tasks import InMemoryTaskStorefrom a2a_agent_executor_recipe import RecipeAgentExecutorrequest_handler = DefaultRequestHandler(agent_executor=RecipeAgentExecutor(),                                        task_store=InMemoryTaskStore())server = A2AStarletteApplication(agent_card=public_agent_card,                                 http_handler=request_handler)import uvicornuvicorn.run(server.build(),             host='0.0.0.0',             port=agent_port)